-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "الدعوة" (dawah) — تستنفد العنقود بالكامل (7 تصنيفات فرعية من
-- أصل 7، كلها بلا محتوى): فضل الدعوة، صفات الداعية، فقه الدعوة
-- وأولوياتها وموازناتها، دعوة غير المسلمين والمسلم الجديد، التعامل مع
-- الشبهات، الدعوة الرقمية، الخطابة وإعداد الدروس.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: أصول الدعوة لعبد
-- الكريم زيدان، الرسول الداعية لعبد الكريم زيدان، فقه الأولويات ليوسف
-- القرضاوي، فقه الدعوة إلى الله لمحمد أحمد الراشد.
-- الآيات المستشهَد بها (فصلت: 33، يوسف: 108، آل عمران: 104، آل عمران:
-- 64، النحل: 125، الأحزاب: 70) تحقَّقت حرفياً من
-- artifacts/majalis/public/data/quran محلياً عبر حقل numberInSurah قبل
-- الإدراج.
-- الأحاديث تحقَّقت عبر WebSearch قبل الإدراج: «من دل على خير فله مثل
-- أجر فاعله» (صحيح مسلم 1893)، حديث بعث معاذ بن جبل إلى اليمن (متفق
-- عليه)، «إن الله رفيق يحب الرفق...» (صحيح مسلم 2593)، «بلغوا عني ولو
-- آية» (صحيح البخاري 3461)، «يسروا ولا تعسروا وبشروا ولا تنفروا»
-- (متفق عليه، البخاري 69 ومسلم 1734).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات السبعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) فضل الدعوة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d57240ae-2715-4972-908d-2045a525987b' AND title='فضل الدعوة إلى الله ومكانتها في الإسلام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فضل الدعوة إلى الله ومكانتها في الإسلام', 'تعريف موجز بمنزلة الدعوة إلى الله في الإسلام وأجرها العظيم عند الله', 'd57240ae-2715-4972-908d-2045a525987b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف الدعوة', 'الدعوة إلى الله هي حث الناس على الخير والهدى، والأمر بالمعروف والنهي عن المنكر، وتبليغهم دين الإسلام بالحكمة والموعظة الحسنة ليؤمنوا بالله ويعملوا بشرعه. وهي وظيفة الأنبياء والرسل جميعًا، وقد ورثها العلماء والدعاة من بعدهم.', 1),
    (v_lesson, 'terms', 'مكانة الدعوة ومنزلتها', 'الدعوة إلى الله من أفضل الأعمال وأزكاها عند الله، لأنها اقتداء بطريق الأنبياء والرسل عليهم السلام، وسبب لهداية الخلق ونشر الخير في الأرض، ولذلك امتدح الله تعالى أهل الدعوة ووصفهم بأنهم أحسن الناس قولاً.', 2),
    (v_lesson, 'evidence', 'أحسن الناس قولاً من دعا إلى الله', 'قال تعالى: ﴿وَمَنْ أَحْسَنُ قَوْلًا مِّمَّن دَعَا إِلَى اللَّهِ وَعَمِلَ صَالِحًا وَقَالَ إِنَّنِي مِنَ الْمُسْلِمِينَ﴾ (فصلت: 33)', 3),
    (v_lesson, 'evidence', 'أجر الدال على الخير', 'عن أبي مسعود عقبة بن عمرو الأنصاري رضي الله عنه أن رجلاً أتى النبي صلى الله عليه وسلم فطلب منه أن يحمله على راحلة، فقال النبي صلى الله عليه وسلم: "ما عندي"، فقال رجل آخر: يا رسول الله، أنا أدله على من يحمله، فقال النبي صلى الله عليه وسلم: "من دل على خير فله مثل أجر فاعله"، رواه مسلم.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول الدعوة — عبد الكريم زيدان', 1);
  END IF;

  -- 2) صفات الداعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='bc7b39fa-a583-468f-b5f6-fbad40ef3fb8' AND title='صفات الداعية الناجح: البصيرة والرفق') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('صفات الداعية الناجح: البصيرة والرفق', 'تعريف موجز بأبرز الصفات التي ينبغي أن يتحلى بها الداعية إلى الله', 'bc7b39fa-a583-468f-b5f6-fbad40ef3fb8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'البصيرة أساس الدعوة', 'من أهم صفات الداعية أن يدعو على بصيرة، أي بعلم ويقين بما يدعو إليه من التوحيد وأحكام الشرع، لا بجهل ولا تقليد أعمى؛ فالداعية الجاهل يضر أكثر مما ينفع، وقد يزين الباطل بحسن نيته وهو لا يشعر.', 1),
    (v_lesson, 'terms', 'الرفق واللين في الدعوة', 'من أعظم صفات الداعية الناجح الرفق بالمدعوين واللين معهم، والصبر على ما يلقاه من أذى أو إعراض، فالرفق يفتح القلوب ويقرب الناس من الحق، بخلاف الشدة والعنف اللذين ينفران الناس ويصدانهم عن الاستجابة.', 2),
    (v_lesson, 'evidence', 'الدعوة على بصيرة', 'قال تعالى: ﴿قُلْ هَٰذِهِ سَبِيلِي أَدْعُو إِلَى اللَّهِ عَلَىٰ بَصِيرَةٍ أَنَا وَمَنِ اتَّبَعَنِي وَسُبْحَانَ اللَّهِ وَمَا أَنَا مِنَ الْمُشْرِكِينَ﴾ (يوسف: 108)', 3),
    (v_lesson, 'evidence', 'محبة الله للرفق', 'عن عائشة رضي الله عنها أن النبي صلى الله عليه وسلم قال: "إن الله رفيق يحب الرفق، ويعطي على الرفق ما لا يعطي على العنف"، رواه مسلم.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الرسول الداعية — عبد الكريم زيدان', 1);
  END IF;

  -- 3) فقه الدعوة وأولوياتها وموازناتها
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b3acc0ab-fc50-4160-8b1e-7a08805e8268' AND title='فقه الأولويات في الدعوة إلى الله') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فقه الأولويات في الدعوة إلى الله', 'تعريف موجز بمفهوم فقه الأولويات في الدعوة وأهمية الترتيب في تقديم الأهم فالمهم', 'b3acc0ab-fc50-4160-8b1e-7a08805e8268', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'مفهوم فقه الأولويات', 'فقه الأولويات في الدعوة هو العلم بترتيب الأمور بحسب أهميتها ومنزلتها في الدين، فيُقدَّم الأهم على المهم، والأصول على الفروع، والفرائض على النوافل، حتى لا يشتغل الداعية بالجزئيات عن الكليات، أو بالمختلف فيه عن المجمع عليه.', 1),
    (v_lesson, 'terms', 'الترتيب الواجب في مضامين الدعوة', 'يبدأ الداعية دعوته بالأصل الأعظم وهو توحيد الله وإفراده بالعبادة، ثم ينتقل إلى أركان الإسلام العملية كالصلاة والزكاة، ثم بقية الشرائع، وهكذا يسير في دعوته على منهج تدريجي يراعي حال المدعو واستعداده، لا أن يبدأ بفروع المسائل قبل استقرار الأصول.', 2),
    (v_lesson, 'evidence', 'الدعوة والأمر بالمعروف كواجب جماعي منظم', 'قال تعالى: ﴿وَلْتَكُن مِّنكُمْ أُمَّةٌ يَدْعُونَ إِلَى الْخَيْرِ وَيَأْمُرُونَ بِالْمَعْرُوفِ وَيَنْهَوْنَ عَنِ الْمُنكَرِ وَأُولَٰئِكَ هُمُ الْمُفْلِحُونَ﴾ (آل عمران: 104)', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه الأولويات — يوسف القرضاوي', 1);
  END IF;

  -- 4) دعوة غير المسلمين والمسلم الجديد
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b0ff2096-ba50-4c28-9f72-eeac7c2af127' AND title='دعوة غير المسلمين: المنهج النبوي ورعاية المسلم الجديد') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('دعوة غير المسلمين: المنهج النبوي ورعاية المسلم الجديد', 'تعريف موجز بمنهج دعوة غير المسلمين كما بيّنه النبي صلى الله عليه وسلم، وأهمية رعاية المسلم الجديد بعد إسلامه', 'b0ff2096-ba50-4c28-9f72-eeac7c2af127', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أساس دعوة غير المسلمين', 'الأصل في دعوة غير المسلمين البدء بدعوتهم إلى كلمة التوحيد قبل أي شيء آخر، بأسلوب يقوم على الحوار الهادئ والدليل العقلي والنقلي المشترك، دون إكراه أو تعنيف، امتثالاً لأمر الله تعالى بدعوة أهل الكتاب إلى كلمة سواء يجتمعون عليها.', 1),
    (v_lesson, 'terms', 'رعاية المسلم الجديد', 'بعد إسلام غير المسلم تقع على الداعية والمجتمع المسلم مسؤولية رعايته، بتعليمه أصول دينه تدريجيًا كما فعل النبي صلى الله عليه وسلم مع معاذ حين أرسله إلى اليمن، وتقديم الدعم له في مواجهة ما قد يلقاه من عزلة اجتماعية أو ضغوط من محيطه السابق.', 2),
    (v_lesson, 'evidence', 'الدعوة إلى كلمة سواء', 'قال تعالى: ﴿قُلْ يَا أَهْلَ الْكِتَابِ تَعَالَوْا إِلَىٰ كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَلَّا نَعْبُدَ إِلَّا اللَّهَ وَلَا نُشْرِكَ بِهِ شَيْئًا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِّن دُونِ اللَّهِ﴾ (آل عمران: 64)', 3),
    (v_lesson, 'evidence', 'منهج التدرج في التعليم بعد الدعوة', 'عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم لما بعث معاذًا رضي الله عنه إلى اليمن قال له: "إنك تأتي قومًا من أهل الكتاب، فليكن أول ما تدعوهم إليه شهادة أن لا إله إلا الله، فإن هم أطاعوا لذلك فأعلمهم أن الله قد افترض عليهم خمس صلوات في كل يوم وليلة..."، متفق عليه.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول الدعوة — عبد الكريم زيدان', 1);
  END IF;

  -- 5) التعامل مع الشبهات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='65db0482-ebd8-40da-9d14-93280ed0a1c6' AND title='التعامل مع الشبهات أثناء الدعوة: أسلوب المجادلة بالحسنى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التعامل مع الشبهات أثناء الدعوة: أسلوب المجادلة بالحسنى', 'تعريف موجز بمنهج الحوار وأسلوب الرد على الشبهات التي تُثار على الداعية أثناء دعوته', '65db0482-ebd8-40da-9d14-93280ed0a1c6', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'منهجية القرآن في الجدال', 'أرشد القرآن الكريم الداعية إلى ثلاث أدوات متدرجة في التعامل مع المدعوين: الحكمة، ثم الموعظة الحسنة، ثم المجادلة بالتي هي أحسن عند الحاجة إلى الرد على شبهة أو اعتراض، فالمجادلة وسيلة استثنائية تُستعمل بأدب ولين لا بالتعالي أو التجريح.', 1),
    (v_lesson, 'terms', 'ضوابط الرد على الشبهات في الحوار', 'يقتضي الرد الحسن على الشبهات أثناء الدعوة أن يفهم الداعية الشبهة أولاً فهمًا صحيحًا، وأن يرد عليها بالحجة العلمية الواضحة دون انفعال، مراعيًا حال المدعو ومستواه الفكري، وقاصدًا هدايته لا مجرد الغلبة عليه في الجدل.', 2),
    (v_lesson, 'evidence', 'الأمر بالمجادلة بالتي هي أحسن', 'قال تعالى: ﴿ادْعُ إِلَىٰ سَبِيلِ رَبِّكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ وَجَادِلْهُم بِالَّتِي هِيَ أَحْسَنُ إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ﴾ (النحل: 125)', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه الدعوة إلى الله — محمد أحمد الراشد', 1);
  END IF;

  -- 6) الدعوة الرقمية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9237102f-c5d0-4297-adae-6dd52533c060' AND title='الدعوة الرقمية: توظيف وسائل التواصل الحديثة في التبليغ') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الدعوة الرقمية: توظيف وسائل التواصل الحديثة في التبليغ', 'تعريف موجز بمفهوم الدعوة الرقمية وضوابط توظيف منصات التواصل الحديثة في تبليغ الدين', '9237102f-c5d0-4297-adae-6dd52533c060', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'مفهوم الدعوة الرقمية', 'الدعوة الرقمية هي توظيف وسائل الاتصال الحديثة كالإنترنت ومنصات التواصل الاجتماعي والفيديو المرئي في تبليغ الدين ونشر العلم الشرعي، وهي امتداد لمبدأ أصيل في الشريعة هو استعمال أنجع الوسائل المباحة المتاحة في كل عصر لتبليغ الدعوة.', 1),
    (v_lesson, 'terms', 'ضوابط الدعوة عبر المنصات الرقمية', 'يشترط في الدعوة الرقمية أن تصدر عن علم شرعي موثوق لا عن تسرع أو رأي بغير دليل، وأن تراعي الأمانة في نقل النصوص وعزوها إلى مصادرها، مع الحرص على الأسلوب الحسن الجاذب الذي يناسب طبيعة هذه الوسائل من إيجاز ووضوح دون إخلال بالمضمون الشرعي.', 2),
    (v_lesson, 'evidence', 'مشروعية التبليغ ولو بالقليل عبر أي وسيلة متاحة', 'عن عبدالله بن عمرو بن العاص رضي الله عنهما أن النبي صلى الله عليه وسلم قال: "بلغوا عني ولو آية"، رواه البخاري.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول الدعوة — عبد الكريم زيدان', 1);
  END IF;

  -- 7) الخطابة وإعداد الدروس
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ea25b763-5572-4082-a935-bd7959777d53' AND title='الخطابة وإعداد الدروس: القول السديد والتيسير على المتلقين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الخطابة وإعداد الدروس: القول السديد والتيسير على المتلقين', 'تعريف موجز بأصول إعداد الخطبة أو الدرس الدعوي وأسلوب إلقائه بما ييسر على المتلقين', 'ea25b763-5572-4082-a935-bd7959777d53', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أصول القول السديد في الخطابة', 'تقوم الخطابة الشرعية الناجحة على القول السديد، وهو الكلام الموافق للحق الواضح المعنى البعيد عن اللبس أو الغموض، بحيث يخرج الخطيب أو المعلم عن الإطناب المخل والإيجاز المخل إلى وضوح يوصل المقصود بأيسر عبارة.', 1),
    (v_lesson, 'terms', 'منهج التيسير في إعداد الدرس', 'من أهم أصول إعداد الدرس أو الموعظة مراعاة حال المستمعين وتيسير المعلومة عليهم بالتدرج من السهل إلى الصعب، والتبشير بفضل العمل الصالح قبل التخويف من عقوبة تركه، حتى لا ينفر المتلقي من الدرس أو ينصرف عنه.', 2),
    (v_lesson, 'evidence', 'الأمر بالقول السديد', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا﴾ (الأحزاب: 70)', 3),
    (v_lesson, 'evidence', 'التيسير والتبشير في التعليم', 'عن أنس بن مالك رضي الله عنه أن النبي صلى الله عليه وسلم قال: "يسروا ولا تعسروا، وبشروا ولا تنفروا"، متفق عليه.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه الدعوة إلى الله — محمد أحمد الراشد', 1);
  END IF;

  -- تحديث حالة التصنيفات السبعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
